// // This is a 3-to-8 line decoder that decodes a 3-bit input 'a' into an 8-bit output 'y', with only one output line high corresponding to the binary value of the input.
module decoder_3to8 (
    input [2:0] a,
    output reg [7:0] y
);

    always @(*) begin
        y = 8'b00000000;
        y[a] = 1;
    end

endmodule
